const row = $input.first().json;

// Usar caché si está completed Y no hubo cambios desde la generación
const use_cache = (
  row.status === 'completed' &&
  row.has_changes === false &&
  row.existing_id != null
);

return { json: { ...row, use_cache } };

parameters.query:
SELECT id, content_md, content_html, use_cases_json, generated_at
FROM cobol_analysis.use_cases
WHERE id = {{ $('Evalúa Caché').first().json.existing_id }}

parameters.jsCode:
const row = $input.first().json;
return {
  json: {
    success:        true,
    from_cache:     true,
    use_cases_json: row.use_cases_json,
    content_md:     row.content_md,
    content_html:   row.content_html,
    generated_at:   row.generated_at
  }
};

const items = $input.all().map(i => i.json);

const programs = items.filter(i => i.tipo === 'program');
const files    = items.filter(i => i.tipo === 'file');
const db2      = items.filter(i => i.tipo === 'db2');

// Construye resumen de programas para el LLM
const programsSummary = programs.map(p => {
  let calls = '';
  try {
    const refs = JSON.parse(p.calls_json || '[]');
    if (refs.length) calls = ` | Llama a: ${refs.join(', ')}`;
  } catch(e) {}
  return `- ${p.nombre} (${p.lineas || '?'} líneas, complejidad ${p.complejidad || '?'}): ${p.descripcion || 'sin descripción'}${calls}`;
}).join('\n');

const filesSummary = files.length
  ? files.map(f => `- ${f.nombre}: usado por [${f.descripcion}]`).join('\n')
  : 'No se detectaron archivos físicos';

const db2Summary = db2.length
  ? db2.map(d => `- ${d.nombre} (${d.descripcion || 'operaciones desconocidas'}): accedido por [${d.calls_json}]`).join('\n')
  : 'No se detectaron accesos DB2';

const context = `PROGRAMAS DEL SISTEMA (${programs.length} programas COBOL):
${programsSummary}

ARCHIVOS DEL SISTEMA:
${filesSummary}

TABLAS DB2:
${db2Summary}`;

return { json: { context, program_count: programs.length } };

const chainOut = $input.first().json;

let raw = (chainOut.text || chainOut.output || '').trim();
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();

let uc;
try {
  uc = JSON.parse(raw);
} catch(e) {
  throw new Error(`LLM no devolvió JSON válido: ${e.message}. Inicio: ${raw.substring(0, 300)}`);
}

// --- Genera Markdown ---
const lines = [];
lines.push(`# ${uc.system_name || 'Sistema'} — Casos de Uso`);
lines.push('');
lines.push(uc.system_description || '');
lines.push('');
lines.push(`**Total de casos de uso:** ${uc.total_use_cases}`);
lines.push('');

for (const group of (uc.groups || [])) {
  lines.push(`---`);
  lines.push(`## ${group.id}: ${group.name}`);
  lines.push('');
  lines.push(group.description || '');
  lines.push('');
  if (group.programs?.length) {
    lines.push(`**Programas:** ${group.programs.join(', ')}`);
    lines.push('');
  }
  for (const u of (group.use_cases || [])) {
    lines.push(`### ${u.id}: ${u.title}`);
    lines.push('');
    lines.push(`| Campo | Detalle |`);
    lines.push(`|-------|---------|`);
    lines.push(`| **Actor** | ${u.actor} |`);
    lines.push(`| **Trigger** | ${u.trigger} |`);
    if (u.programs_involved?.length) lines.push(`| **Programas** | ${u.programs_involved.join(', ')} |`);
    if (u.db2_tables?.length)        lines.push(`| **Tablas DB2** | ${u.db2_tables.join(', ')} |`);
    if (u.files?.length)             lines.push(`| **Archivos** | ${u.files.join(', ')} |`);
    lines.push('');
    if (u.preconditions?.length) {
      lines.push(`**Precondiciones:**`);
      u.preconditions.forEach(p => lines.push(`- ${p}`));
      lines.push('');
    }
    lines.push(`**Flujo principal:**`);
    (u.main_flow || []).forEach(s => lines.push(s));
    lines.push('');
    if (u.alternative_flows?.length) {
      lines.push(`**Flujos alternativos:**`);
      u.alternative_flows.forEach(af => {
        lines.push(`- **${af.id}** — ${af.condition}`);
        (af.steps || []).forEach(s => lines.push(`  - ${s}`));
      });
      lines.push('');
    }
    if (u.postconditions?.length) {
      lines.push(`**Postcondiciones:**`);
      u.postconditions.forEach(p => lines.push(`- ${p}`));
      lines.push('');
    }
    if (u.notes) {
      lines.push(`> **Nota técnica:** ${u.notes}`);
      lines.push('');
    }
  }
}

const content_md = lines.join('\n');

// --- Genera HTML ---
const escHtml = s => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

const groupsHtml = (uc.groups || []).map(group => {
  const ucsHtml = (group.use_cases || []).map(u => `
    <div class="uc-card" id="${u.id}">
      <div class="uc-header">
        <span class="uc-id">${u.id}</span>
        <h3>${escHtml(u.title)}</h3>
      </div>
      <div class="uc-body">
        <div class="uc-meta">
          <span><strong>Actor:</strong> ${escHtml(u.actor)}</span>
          <span><strong>Trigger:</strong> ${escHtml(u.trigger)}</span>
          ${u.programs_involved?.length ? `<span><strong>Programas:</strong> ${u.programs_involved.map(p => `<code>${p}</code>`).join(' ')}</span>` : ''}
          ${u.db2_tables?.length ? `<span><strong>DB2:</strong> ${u.db2_tables.join(', ')}</span>` : ''}
          ${u.files?.length ? `<span><strong>Archivos:</strong> ${u.files.join(', ')}</span>` : ''}
        </div>
        ${u.preconditions?.length ? `<div class="uc-section"><strong>Precondiciones</strong><ul>${u.preconditions.map(p => `<li>${escHtml(p)}</li>`).join('')}</ul></div>` : ''}
        <div class="uc-section"><strong>Flujo principal</strong><ol>${(u.main_flow||[]).map(s => `<li>${escHtml(s.replace(/^\d+\.\s*/,''))}</li>`).join('')}</ol></div>
        ${u.alternative_flows?.length ? `<div class="uc-section"><strong>Flujos alternativos</strong>${u.alternative_flows.map(af => `<div class="alt-flow"><span class="alt-id">${af.id}</span> <em>${escHtml(af.condition)}</em><ul>${(af.steps||[]).map(s=>`<li>${escHtml(s)}</li>`).join('')}</ul></div>`).join('')}</div>` : ''}
        ${u.postconditions?.length ? `<div class="uc-section"><strong>Postcondiciones</strong><ul>${u.postconditions.map(p => `<li>${escHtml(p)}</li>`).join('')}</ul></div>` : ''}
        ${u.notes ? `<div class="uc-note">📌 ${escHtml(u.notes)}</div>` : ''}
      </div>
    </div>`).join('');

  return `
  <section class="group" id="${group.id}">
    <div class="group-header">
      <h2><span class="group-id">${group.id}</span> ${escHtml(group.name)}</h2>
      <p>${escHtml(group.description || '')}</p>
      ${group.programs?.length ? `<div class="program-tags">${group.programs.map(p=>`<code>${p}</code>`).join(' ')}</div>` : ''}
    </div>
    ${ucsHtml}
  </section>`;
}).join('');

const tocHtml = (uc.groups || []).map(g =>
  `<li><a href="#${g.id}">${g.id}: ${escHtml(g.name)}</a>
    <ul>${(g.use_cases||[]).map(u => `<li><a href="#${u.id}">${u.id}: ${escHtml(u.title)}</a></li>`).join('')}</ul>
  </li>`
).join('');

const content_html = `<!DOCTYPE html>
<html lang="es">
<head><meta charset="UTF-8">
<style>
  *{box-sizing:border-box;}
  body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;margin:0;display:flex;min-height:100vh;color:#111;}
  nav{width:260px;min-width:260px;background:#1e3a5f;color:#fff;padding:24px 16px;position:sticky;top:0;height:100vh;overflow-y:auto;}
  nav h2{font-size:13px;text-transform:uppercase;letter-spacing:.05em;color:#93c5fd;margin:0 0 12px;}
  nav ul{list-style:none;padding:0;margin:0;}
  nav li{margin-bottom:4px;}
  nav a{color:#bfdbfe;text-decoration:none;font-size:13px;display:block;padding:2px 4px;border-radius:3px;}
  nav a:hover{background:#2563eb;color:#fff;}
  nav ul ul{padding-left:12px;margin-top:2px;}
  nav ul ul a{font-size:12px;color:#93c5fd;}
  main{flex:1;padding:32px;max-width:900px;}
  .sys-header{margin-bottom:32px;}
  .sys-header h1{font-size:24px;color:#1e3a5f;margin:0 0 8px;}
  .sys-header p{color:#374151;margin:0 0 8px;}
  .sys-header .badge{display:inline-block;background:#dbeafe;color:#1e40af;padding:4px 12px;border-radius:20px;font-size:13px;}
  .group{margin-bottom:40px;}
  .group-header{background:#eff6ff;border-left:4px solid #3b82f6;padding:16px 20px;border-radius:0 8px 8px 0;margin-bottom:16px;}
  .group-header h2{margin:0 0 4px;font-size:18px;color:#1e3a5f;display:flex;align-items:center;gap:10px;}
  .group-id{background:#3b82f6;color:#fff;padding:2px 8px;border-radius:4px;font-size:13px;font-weight:600;}
  .group-header p{margin:4px 0 8px;color:#374151;font-size:14px;}
  .program-tags code{background:#dbeafe;color:#1e40af;padding:2px 6px;border-radius:3px;font-size:12px;margin-right:4px;}
  .uc-card{background:#fff;border:1px solid #e5e7eb;border-radius:8px;margin-bottom:14px;box-shadow:0 1px 3px rgba(0,0,0,.06);overflow:hidden;}
  .uc-header{display:flex;align-items:center;gap:12px;padding:12px 16px;background:#f8fafc;border-bottom:1px solid #e5e7eb;}
  .uc-id{background:#1e3a5f;color:#fff;padding:2px 8px;border-radius:4px;font-size:12px;font-weight:600;white-space:nowrap;}
  .uc-header h3{margin:0;font-size:15px;color:#111;}
  .uc-body{padding:16px;}
  .uc-meta{display:flex;flex-wrap:wrap;gap:12px;margin-bottom:12px;font-size:13px;color:#374151;}
  .uc-meta span{background:#f3f4f6;padding:4px 10px;border-radius:4px;}
  .uc-meta code{background:#dbeafe;color:#1e40af;padding:1px 5px;border-radius:3px;font-size:11px;}
  .uc-section{margin-bottom:12px;font-size:14px;}
  .uc-section strong{display:block;color:#374151;margin-bottom:4px;font-size:13px;text-transform:uppercase;letter-spacing:.03em;}
  .uc-section ol,.uc-section ul{margin:0;padding-left:20px;}
  .uc-section li{margin-bottom:3px;}
  .alt-flow{background:#fffbeb;border-left:3px solid #f59e0b;padding:6px 10px;margin-bottom:6px;border-radius:0 4px 4px 0;font-size:13px;}
  .alt-id{background:#f59e0b;color:#fff;padding:1px 6px;border-radius:3px;font-size:11px;font-weight:600;margin-right:6px;}
  .uc-note{background:#f0fdf4;border-left:3px solid #22c55e;padding:8px 12px;border-radius:0 4px 4px 0;font-size:13px;color:#166534;margin-top:8px;}
</style>
</head>
<body>
<nav>
  <h2>Índice</h2>
  <ul>${tocHtml}</ul>
</nav>
<main>
  <div class="sys-header">
    <h1>${escHtml(uc.system_name || 'Sistema')}</h1>
    <p>${escHtml(uc.system_description || '')}</p>
    <span class="badge">${uc.total_use_cases} casos de uso</span>
  </div>
  ${groupsHtml}
</main>
</body></html>`;

return {
  json: {
    use_cases_json: JSON.stringify(uc),
    content_md,
    content_html
  }
};

