parameters.jsCode:
const data = $('Parsea y Genera Docs').first().json;
const uc   = JSON.parse(data.use_cases_json);
return {
  json: {
    success:        true,
    from_cache:     false,
    total_use_cases:uc.total_use_cases,
    groups:         uc.groups?.length,
    use_cases_json: data.use_cases_json,
    content_md:     data.content_md,
    content_html:   data.content_html,
    generated_at:   new Date().toISOString()
  }
};
